    public Object parseCurrency(Object rawCurrency)
    {
        Object id = this.safeString(rawCurrency, "symbol");
        Object code = this.safeCurrencyCode(id);
        Object name = this.safeString(rawCurrency, "name");
        Object networks = new java.util.HashMap<String, Object>() {{}};
        Object chains = this.safeList(rawCurrency, "binding_gateways", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object currencyMaxPrecision = this.parsePrecision(this.safeString2(rawCurrency, "withdrawal_scale", "scale"));
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(chains)); j++)
        {
            Object chain = Helpers.GetValue(chains, j);
            Object networkId = this.safeString(chain, "gateway_name");
            Object networkCode = this.networkIdToCode(networkId, code);
            Object deposit = this.safeBool(chain, "is_deposit_enabled");
            Object withdraw = this.safeBool(chain, "is_withdrawal_enabled");
            Object minDepositAmount = this.safeString(chain, "min_deposit_amount");
            Object minWithdrawalAmount = this.safeString(chain, "min_withdrawal_amount");
            Object withdrawalFee = this.safeString(chain, "withdrawal_fee");
            Object precision = this.parsePrecision(this.safeString2(chain, "withdrawal_scale", "scale"));
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "id", networkId );
    put( "network", networkCode );
    put( "margin", null );
    put( "deposit", deposit );
    put( "withdraw", withdraw );
    put( "active", null );
    put( "fee", BigoneCore.this.parseNumber(withdrawalFee) );
    put( "precision", BigoneCore.this.parseNumber(precision) );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", minDepositAmount );
            put( "max", null );
        }} );
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", minWithdrawalAmount );
            put( "max", null );
        }} );
    }} );
    put( "info", chain );
}});
        }
        Object chainLength = Helpers.getArrayLength(chains);
        Object type = null;
        if (Helpers.isTrue(this.safeBool(rawCurrency, "is_fiat")))
        {
            type = "fiat";
        } else if (Helpers.isTrue(Helpers.isEqual(chainLength, 0)))
        {
            if (Helpers.isTrue(this.isLeveragedCurrency(id)))
            {
                type = "leveraged";
            } else
            {
                type = "other";
            }
        } else
        {
            type = "crypto";
        }
        final Object finalType = type;
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "code", code );
            put( "info", rawCurrency );
            put( "name", name );
            put( "type", finalType );
            put( "active", null );
            put( "deposit", null );
            put( "withdraw", null );
            put( "fee", null );
            put( "precision", BigoneCore.this.parseNumber(currencyMaxPrecision) );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", networks );
        }});
    }

