                //            ...
                //            '34578.5': '66367'
                //        },
                //        to: '59737174',
                //        lastPrice: '34554.5',
                //        bestPrices: {
                //            ask: '34557.0',
                //            bid: '34552.0'
                //        },
                //        from: '0'
                //    }
                //
                return this.parseContractOrderBook(response, Helpers.GetValue(market, "symbol"), limit);
