    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //    {
        //        "id": "42154072252",
        //        "asset_pair_name": "SOL-USDT",
        //        "price": "20",
        //        "amount": "0.5",
        //        "filled_amount": "0",
        //        "avg_deal_price": "0",
        //        "side": "ASK",
        //        "state": "PENDING",
        //        "created_at": "2023-09-13T03:42:00Z",
        //        "updated_at": "2023-09-13T03:42:00Z",
        //        "type": "LIMIT",
        //        "stop_price": "0",
        //        "immediate_or_cancel": false,
        //        "post_only": false,
        //        "client_order_id": ''
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "id");
        Object marketId = this.safeString(order, "asset_pair_name");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object timestamp = this.parse8601(this.safeString(order, "created_at"));
        Object side = this.safeString(order, "side");
        if (Helpers.isTrue(Helpers.isEqual(side, "BID")))
        {
            side = "buy";
        } else
        {
            side = "sell";
        }
        Object triggerPrice = this.safeString(order, "stop_price");
        if (Helpers.isTrue(Precise.stringEq(triggerPrice, "0")))
        {
            triggerPrice = null;
        }
        Object immediateOrCancel = this.safeBool(order, "immediate_or_cancel");
        Object timeInForce = null;
        if (Helpers.isTrue(immediateOrCancel))
        {
            timeInForce = "IOC";
        }
        Object type = this.parseType(this.safeString(order, "type"));
        Object price = this.safeString(order, "price");
        Object amount = null;
        Object filled = null;
        Object cost = null;
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(type, "market")) && Helpers.isTrue(Helpers.isEqual(side, "buy"))))
        {
            cost = this.safeString(order, "filled_amount");
        } else
        {
            amount = this.safeString(order, "amount");
            filled = this.safeString(order, "filled_amount");
        }
        final Object finalType = type;
        final Object finalTimeInForce = timeInForce;
        final Object finalSide = side;
        final Object finalTriggerPrice = triggerPrice;
        final Object finalAmount = amount;
        final Object finalCost = cost;
        final Object finalFilled = filled;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", BigoneCore.this.safeString(order, "client_order_id") );
            put( "timestamp", timestamp );
            put( "datetime", BigoneCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", BigoneCore.this.parse8601(BigoneCore.this.safeString(order, "updated_at")) );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", finalTimeInForce );
            put( "postOnly", BigoneCore.this.safeBool(order, "post_only") );
            put( "side", finalSide );
            put( "price", price );
            put( "triggerPrice", finalTriggerPrice );
            put( "amount", finalAmount );
            put( "cost", finalCost );
            put( "average", BigoneCore.this.safeString(order, "avg_deal_price") );
            put( "filled", finalFilled );
            put( "remaining", null );
            put( "status", BigoneCore.this.parseOrderStatus(BigoneCore.this.safeString(order, "state")) );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

